import os
import boto3
import subprocess
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from botocore.exceptions import NoCredentialsError

app = Flask(__name__)

# AWS Configuration
AWS_ACCESS_KEY_ID = 'YOUR_AWS_ACCESS_KEY_ID'
AWS_SECRET_ACCESS_KEY = 'YOUR_AWS_SECRET_ACCESS_KEY'
AWS_REGION = 'YOUR_AWS_REGION'
S3_BUCKET = 'YOUR_S3_BUCKET'

s3 = boto3.client('s3', region_name=AWS_REGION,
                  aws_access_key_id=AWS_ACCESS_KEY_ID,
                  aws_secret_access_key=AWS_SECRET_ACCESS_KEY)

def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--window-size=1280x720")

    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)
    screenshot_filename = '/tmp/screenshot.png'
    driver.save_screenshot(screenshot_filename)
    driver.quit()
    return screenshot_filename

def upload_to_s3(file_name, bucket, object_name=None):
    if object_name is None:
        object_name = os.path.basename(file_name)

    try:
        s3.upload_file(file_name, bucket, object_name)
        return f"https://{bucket}.s3.amazonaws.com/{object_name}"
    except FileNotFoundError:
        return None
    except NoCredentialsError:
        return None

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json['url']
    thumbnail_path = take_screenshot(url)
    s3_url = upload_to_s3(thumbnail_path, S3_BUCKET)
    if s3_url:
        return jsonify({'s3_url': s3_url}), 200
    else:
        return jsonify({'error': 'Failed to upload screenshot'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=80)